import React from 'react';

function BookingGrid({ classrooms, timeslots, bookings, selectedDate, onCreateBooking, onCancelBooking, user }) {

  const handleBookClick = (classroomId, timeslotId) => {
    const grade = prompt("請輸入使用年級：");
    if (!grade) return; // 使用者取消
    const purpose = prompt("請輸入事由：");
    if (!purpose) return; // 使用者取消

    onCreateBooking({
      classroomId: classroomId,
      timeslotId: timeslotId,
      bookingDate: selectedDate,
      grade: grade,
      purpose: purpose
    });
  };

  return (
    <div className="booking-grid-container">
      <table>
        <thead>
          <tr>
            {/* 表頭第一格是空的或顯示"時段" */}
            <th>時段</th>
            {/* 表頭現在是教室名稱 */}
            {classrooms.map(room => (
              <th key={room.id}>{room.name}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {/* 外層迴圈現在是遍歷 timeslots */}
          {timeslots.map(slot => (
            <tr key={slot.id}>
              {/* 每一行的第一格是時段名稱和時間 */}
              <td>
                <strong>{slot.name}</strong><br/>
                ({slot.start_time} - {slot.end_time})
              </td>

              {/* 內層迴圈是遍歷 classrooms，來產生這一行中對應的格子 */}
              {classrooms.map(room => {
                // 尋找對應這個格子(時段+教室)的預約
                const booking = bookings.find(
                  b => b.timeslot_id === slot.id && b.classroom_id === room.id
                );

                return (
                  <td key={room.id}>
                    {booking ? (
                      <div className="booking-cell booked">
                        <p><strong>年級:</strong> {booking.grade}</p>
                        <p><strong>事由:</strong> {booking.purpose}</p>
                        {user?.role === 'admin' && 
                          <button onClick={() => onCancelBooking(booking.id)} className="cancel-button">
                            取消
                          </button>
                        }
                      </div>
                    ) : (
                      <div className="booking-cell available">
                        {user?.role === 'admin' && 
                          <button onClick={() => handleBookClick(room.id, slot.id)}>
                            登記
                          </button>
                        }
                      </div>
                    )}
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default BookingGrid;
